import json
import re

# Businesses that received reviews in 2018
review_businesses = locals()['var_functions.query_db:20']

# Get business data
business_data = locals()['var_functions.query_db:30']

# Create a lookup for business data
business_lookup = {}
for business in business_data:
    business_lookup[business['business_id']] = business

# Check which of our 2018 review businesses we have data for
business_ids_from_reviews = []
for item in review_businesses:
    ref_id = item['business_ref']
    match = re.search(r'businessref_(\d+)', ref_id)
    if match:
        num = match.group(1)
        business_id = f'businessid_{num}'
        business_ids_from_reviews.append(business_id)

# Now check parking for businesses we have data for
businesses_with_parking = 0
businesses_checked = 0
parking_details = []

for business_id in business_ids_from_reviews:
    if business_id in business_lookup:
        businesses_checked += 1
        business = business_lookup[business_id]
        attributes = business.get('attributes', {})

        if attributes == "None" or not attributes:
            continue

        has_business_parking = False
        has_bike_parking = False

        # Check BusinessParking
        if 'BusinessParking' in attributes:
            bp = attributes['BusinessParking']
            if bp and bp != "None":
                # If it's a string representation of dict, check if any value is True
                if isinstance(bp, str) and 'True' in bp:
                    has_business_parking = True
                elif bp != "None" and bp != "":
                    has_business_parking = True

        # Check BikeParking
        if 'BikeParking' in attributes:
            bike = attributes['BikeParking']
            if bike == True or bike == 'True':
                has_bike_parking = True

        if has_business_parking or has_bike_parking:
            businesses_with_parking += 1
            parking_details.append({
                'business_id': business_id,
                'has_business_parking': has_business_parking,
                'has_bike_parking': has_bike_parking
            })

print('__RESULT__:')
print(json.dumps({
    'total_businesses_from_2018_reviews': len(business_ids_from_reviews),
    'businesses_with_complete_data': businesses_checked,
    'businesses_offering_parking': businesses_with_parking,
    'parking_details': parking_details
}))

